const jwt = require('jsonwebtoken');
const config = {
  secret: 'mysecret', // replace with your own secret key!
  issuer: 'myapp',  // replace with your own issuer name!
  audience: 'myapp'   // replace with your own audience name!
};


// Middleware to verify the token and extract user information.
function authMiddleware(req, res, next) {

  const token = req.headers['x-access-token'];

  if (!token || !token.startsWith('Bearer ')) return res.status(401).json({
    error: 'No token provided.'
  });

  jwt.verify(token.slice(7), config.secret, function (err, decoded) {

    // If the token is invalid or expired, return a 403 status code.
    if (err || !decoded)
      return res.status(401).json({
        error: 'Invalid token.'
      });

    req.user = decoded;
    next();
  });
}